## Simple Checks

```javascript
app.post('/books', (req, res) => {
  const { title, author, year } = req.body;

  if (!title || typeof title !== 'string') {
    return res.status(400).json({ error: 'Title is required and must be a string' });
  }
  if (!author || typeof author !== 'string') {
    return res.status(400).json({ error: 'Author is required and must be a string' });
  }
  if (year && (typeof year !== 'number' || year < 0 || year > new Date().getFullYear())) {
    return res.status(400).json({ error: 'Year must be a valid number' });
  }

  // proceed
});
```

This quickly becomes repetitive. Libraries help.

## express-validator

Install: `npm install express-validator`

```javascript
const { body, validationResult } = require('express-validator');

app.post('/books',
  body('title').notEmpty().isString(),
  body('author').notEmpty().isString(),
  body('year').optional().isInt({ min: 1000, max: new Date().getFullYear() }),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ errors: errors.array() });
    }
    // create book
  }
);
```

It provides a clean way to define validation rules and collect errors.

## Consistent Error Responses

Define an error-handling middleware to format all errors uniformly.

```javascript
// Custom error class
class AppError extends Error {
  constructor(message, statusCode) {
    super(message);
    this.statusCode = statusCode;
  }
}

// In routes, throw new AppError('Not found', 404);

// Error handler middleware
app.use((err, req, res, next) => {
  const { statusCode = 500, message } = err;
  res.status(statusCode).json({
    error: {
      message,
      status: statusCode
    }
  });
});
```
